  `updated_on` varchar(20) NOT NULL,
  `active_status` int(11) DEFAULT 1 COMMENT '1=>ACTIVE,2=>INACTIVE,3=>GRADUATE',
  `active_status_date` date DEFAULT NULL,
  `agreement_doc` varchar(255) DEFAULT NULL,
  `incubation_start` date DEFAULT NULL,
  `incubation_end` date DEFAULT NULL,
  `incubator_equity` decimal(5,2) DEFAULT NULL,
  `is_incubator_send` int(11) DEFAULT 0,
  PRIMARY KEY (`id`),
  KEY `user_id` (`user_id`,`connect_to`),
  KEY `uniq_user_connect` (`user_id`,`connect_to`,`is_incubator_send`)
) ENGINE=InnoDB AUTO_INCREMENT=29020 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

